1	//! Crate-wide error types for beamr.
2	//!
3	//! All runtime failures are represented as values, never panics.
4	//! Process-level errors become exit reasons; loader errors prevent
5	//! module registration; interpreter errors halt the faulting process.
6	
7	use std::error::Error;
8	use std::fmt;
9	
10	/// Failures that can occur while loading and validating BEAM bytecode.
11	#[derive(Debug, Clone, PartialEq, Eq)]
12	pub enum LoadError {
13	    /// The input is not a valid BEAM file or uses an unsupported container shape.
14	    InvalidFormat,
15	    /// A required BEAM chunk is absent from the module being loaded.
16	    MissingChunk(String),
17	    /// Bytecode or chunk payload decoding failed.
18	    DecodeError(String),
19	    /// Decoded module contents failed semantic validation.
20	    ValidationError(String),
21	}
22	
23	impl fmt::Display for LoadError {
24	    fn fmt(&self, formatter: &mut fmt::Formatter<'_>) -> fmt::Result {
25	        match self {
26	            Self::InvalidFormat => formatter.write_str("invalid BEAM file format"),
27	            Self::MissingChunk(chunk) => write!(formatter, "missing required BEAM chunk: {chunk}"),
28	            Self::DecodeError(message) => {
29	                write!(formatter, "failed to decode BEAM data: {message}")
30	            }
31	            Self::ValidationError(message) => {
32	                write!(formatter, "BEAM module validation failed: {message}")
33	            }
34	        }
35	    }
36	}
37	
38	impl Error for LoadError {}
39	
40	/// Failures that can occur while executing BEAM code.
41	#[derive(Debug, Clone, PartialEq, Eq)]
42	pub enum ExecError {
43	    /// A pattern match failed.
44	    Badmatch,
45	    /// No function clause matched the provided arguments.
46	    FunctionClause,
47	    /// The target module, function, or arity is undefined.
48	    Undef,
49	    /// An arithmetic operation failed.
50	    Badarith,
51	    /// User code exited explicitly.
52	    UserExit,
53	}
54	
55	impl fmt::Display for ExecError {
56	    fn fmt(&self, formatter: &mut fmt::Formatter<'_>) -> fmt::Result {
57	        match self {
58	            Self::Badmatch => formatter.write_str("pattern match failed"),
59	            Self::FunctionClause => formatter.write_str("no matching function clause"),
60	            Self::Undef => formatter.write_str("undefined function"),
61	            Self::Badarith => formatter.write_str("arithmetic operation failed"),
62	            Self::UserExit => formatter.write_str("process exited explicitly"),
63	        }
64	    }
65	}
66	
67	impl Error for ExecError {}
68	
69	/// Top-level error type for beamr operations.
70	#[derive(Debug, Clone, PartialEq, Eq)]
71	pub enum BeamrError {
72	    /// A module loading failure.
73	    Load(LoadError),
74	    /// A runtime execution failure.
75	    Exec(ExecError),
76	}
77	
78	impl From<LoadError> for BeamrError {
79	    fn from(error: LoadError) -> Self {
80	        Self::Load(error)
81	    }
82	}
83	
84	impl From<ExecError> for BeamrError {
85	    fn from(error: ExecError) -> Self {
86	        Self::Exec(error)
87	    }
88	}
89	
90	impl fmt::Display for BeamrError {
91	    fn fmt(&self, formatter: &mut fmt::Formatter<'_>) -> fmt::Result {
92	        match self {
93	            Self::Load(error) => write!(formatter, "load error: {error}"),
94	            Self::Exec(error) => write!(formatter, "execution error: {error}"),
95	        }
96	    }
97	}
98	
99	impl Error for BeamrError {
100	    fn source(&self) -> Option<&(dyn Error + 'static)> {
101	        match self {
102	            Self::Load(error) => Some(error),
103	            Self::Exec(error) => Some(error),
104	        }
105	    }
106	}
107	
108	#[cfg(test)]
109	mod tests {
110	    use super::{BeamrError, ExecError, LoadError};
111	
112	    #[test]
113	    fn load_error_display_is_human_readable() {
114	        let formatted = LoadError::MissingChunk("Atom".into()).to_string();
115	
116	        assert!(!formatted.is_empty());
117	        assert!(formatted.contains("missing required BEAM chunk"));
118	        assert!(formatted.contains("Atom"));
119	    }
120	
121	    #[test]
122	    fn exec_error_display_is_human_readable() {
123	        let formatted = ExecError::Badarith.to_string();
124	
125	        assert!(!formatted.is_empty());
126	        assert!(formatted.contains("arithmetic"));
127	    }
128	
129	    #[test]
130	    fn beamr_error_wraps_load_errors() {
131	        let error = BeamrError::from(LoadError::InvalidFormat);
132	
133	        assert!(matches!(error, BeamrError::Load(LoadError::InvalidFormat)));
134	        assert!(!error.to_string().is_empty());
135	    }
136	
137	    #[test]
138	    fn beamr_error_wraps_exec_errors() {
139	        let error = BeamrError::from(ExecError::Badarith);
140	
141	        assert!(matches!(error, BeamrError::Exec(ExecError::Badarith)));
142	        assert!(!error.to_string().is_empty());
143	    }
144	}

